#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=105;
int n,op;
unordered_map<string,int> mp;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	while(n--)
	{
		cin>>op;
		if(op==1)
		{
			string s,a,b;
			int k;
			cin>>s>>k;
			int mx=0;
			for(int i=1;i<=k;i++)
			{
				cin>>a>>b;
				if(a=="short") mx=max(mx,2);
				else if(a=="byte") mx=max(mx,1);
				else if(a=="int") mx=max(mx,4);
				else if(a=="long") mx=max(mx,8);
				else mx=max(mx,mp[a]);
			}
			mp[s]=mx*k;
			cout<<mx*k<<" "<<mx<<"\n";
		}
	}
	return 0;
}
